import{_ as a,o as i,c as n,a2 as l}from"./chunks/framework.BWuWLRhz.js";const k=JSON.parse('{"title":"GTCommission 快速开始","description":"","frontmatter":{},"headers":[],"relativePath":"gtcommission/index.md","filePath":"gtcommission/index.md","lastUpdated":null}'),t={name:"gtcommission/index.md"};function e(p,s,h,o,d,c){return i(),n("div",null,[...s[0]||(s[0]=[l(`<h1 id="gtcommission-快速开始" tabindex="-1">GTCommission 快速开始 <a class="header-anchor" href="#gtcommission-快速开始" aria-label="Permalink to &quot;GTCommission 快速开始&quot;">​</a></h1><p>GTCommission 是每日委托、周期任务和玩家悬赏插件。生存服可以用它做挖矿、钓鱼、收集物资、周常和玩家求购；MMORPG 服务器可以接 MythicMobs、GTMobDrops、GTGather 和副本通关任务。</p><p>委托与悬赏是两套独立入口：</p><table tabindex="0"><thead><tr><th>入口</th><th>用途</th></tr></thead><tbody><tr><td><code>/gtdaily</code></td><td>打开默认委托面板</td></tr><tr><td><code>/gtdaily &lt;面板ID&gt;</code></td><td>打开指定委托面板</td></tr><tr><td><code>/gtbounty</code></td><td>打开悬赏大厅</td></tr><tr><td><code>/gtbounty publish</code></td><td>发布服主开放的悬赏</td></tr><tr><td><code>/gtcom</code></td><td>打开默认委托面板</td></tr></tbody></table><h2 id="安装要求" tabindex="-1">安装要求 <a class="header-anchor" href="#安装要求" aria-label="Permalink to &quot;安装要求&quot;">​</a></h2><ul><li>Minecraft 1.12.2 - 1.21.11。</li><li>GTCore 1.0.49 或更高版本。</li><li>使用 PAPI 条件、自定义经济或 PAPI 显示时安装 PlaceholderAPI。</li><li>使用金币悬赏时安装 Vault 和任意 Vault 经济插件。</li><li>使用 PlayerPoints、DreamPoints 时安装对应插件。</li></ul><h2 id="安装步骤" tabindex="-1">安装步骤 <a class="header-anchor" href="#安装步骤" aria-label="Permalink to &quot;安装步骤&quot;">​</a></h2><ol><li>把 GTCore 和 GTCommission 放进服务端 <code>plugins</code> 文件夹。</li><li>完整启动服务器一次。</li><li>确认控制台显示 GTCommission 已启用。</li><li>输入 <code>/gtdaily</code> 检查默认委托面板。</li><li>输入 <code>/gtbounty</code> 检查悬赏大厅。</li><li>修改配置后输入 <code>/gtcom reload</code>。</li></ol><p>首次启动后生成：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>plugins/GTCommission/</span></span>
<span class="line"><span>  config.yml</span></span>
<span class="line"><span>  messages.yml</span></span>
<span class="line"><span>  tasks/</span></span>
<span class="line"><span>  pools/</span></span>
<span class="line"><span>  boards/</span></span>
<span class="line"><span>  bounties/</span></span>
<span class="line"><span>  guis/</span></span>
<span class="line"><span>    commission/</span></span>
<span class="line"><span>    bounty/</span></span>
<span class="line"><span>  data/</span></span></code></pre></div><p>这些目录都支持继续创建子目录。任务多时可以按玩法分类：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>tasks/</span></span>
<span class="line"><span>  survival/</span></span>
<span class="line"><span>    mining.yml</span></span>
<span class="line"><span>    farming.yml</span></span>
<span class="line"><span>  rpg/</span></span>
<span class="line"><span>    mythic.yml</span></span>
<span class="line"><span>    dungeon.yml</span></span>
<span class="line"><span>  events/</span></span>
<span class="line"><span>    summer.yml</span></span></code></pre></div><p>文件名不决定任务 ID。任务 ID 以配置节点名为准，同一个目录中不能出现重复 ID。</p><h2 id="默认内容" tabindex="-1">默认内容 <a class="header-anchor" href="#默认内容" aria-label="Permalink to &quot;默认内容&quot;">​</a></h2><p>默认配置包含：</p><ul><li>生存挖矿、狩猎、钓鱼、合成、提交原木。</li><li>MythicMobs 怪物、GTMobDrops 物品、GTGather 采集、副本通关。</li><li>PAPI 条件提交任务。</li><li>每日、每周、每月和 NPC 支线面板示例。</li><li>怪物讨伐、玩家追缉、物资征集悬赏示例。</li></ul><p>默认只开启 <code>default</code> 委托面板、怪物讨伐悬赏和物资征集悬赏。周常、月常、NPC 示例和玩家追缉默认关闭。</p><h2 id="第一个独立-npc-委托" tabindex="-1">第一个独立 NPC 委托 <a class="header-anchor" href="#第一个独立-npc-委托" aria-label="Permalink to &quot;第一个独立 NPC 委托&quot;">​</a></h2><p>创建 <code>boards/blacksmith.yml</code>：</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">enabled</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&amp;6铁匠委托&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">gui</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">default</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">tasks</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">submit_logs</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">selection-count</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">conditions</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: []</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">refresh</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  mode</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">DAILY</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  timezone</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Asia/Shanghai</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  hour</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">4</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  minute</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span></span></code></pre></div><p>让 NPC 执行：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>gtdaily open blacksmith %player%</span></span></code></pre></div><p>这个面板拥有自己的刷新时间、任务进度、连续完成次数和 GUI。它不会和默认 <code>/gtdaily</code> 面板混在一起。</p><h2 id="第一次测试顺序" tabindex="-1">第一次测试顺序 <a class="header-anchor" href="#第一次测试顺序" aria-label="Permalink to &quot;第一次测试顺序&quot;">​</a></h2><ol><li>保持 <code>storage.backend: local</code>。</li><li>先测试默认挖矿任务能否增加进度。</li><li>测试提交物品任务能否扣除物品并领取奖励。</li><li>确认 <code>/gtcom reload</code> 没有报错。</li><li>配好经济后发布一条最低奖励悬赏。</li><li>用第二名玩家接取并完成。</li><li>最后再开启 MySQL、Redis、跨服和副本联动。</li></ol><h2 id="文档入口" tabindex="-1">文档入口 <a class="header-anchor" href="#文档入口" aria-label="Permalink to &quot;文档入口&quot;">​</a></h2><ul><li><a href="./config-storage">主配置与存储</a></li><li><a href="./economy">多经济</a></li><li><a href="./tasks">任务配置</a></li><li><a href="./pools-boards">任务池与面板</a></li><li><a href="./bounties">玩家悬赏</a></li><li><a href="./gui">GUI 配置</a></li><li><a href="./commands">命令与权限</a></li><li><a href="./placeholders">PAPI 变量</a></li><li><a href="./compatibility">联动与排错</a></li></ul>`,27)])])}const g=a(t,[["render",e]]);export{k as __pageData,g as default};
